const raw = $json || {};
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const dossier_id = input.dossier_id || input.dossierId || input.dossier_context?.dossier_id || 'DOSSIER-UNSPECIFIED';
const route_id = input.route_id || input.routeId || 'ROUTE_PHASE1_STANDARD';
const user_mode = input.user_mode || input.userMode || 'operator';
const intent_id = input.intent_id || input.intentId || 'unknown';
const user_message = input.user_message || input.userMessage || '';
return [{ json: { ...input, ...$json, dossier_id, route_id, user_mode, intent_id, user_message, dossier_context: { dossier_id, route_id, loaded_at: new Date().toISOString() } } }];

const routeId = $json.route_id || 'ROUTE_PHASE1_STANDARD';
let nextWorkflow = 'WF-100';
let orchestration_decision = 'STANDARD_PATH';
const routeMap = {
  'ROUTE_PHASE1_STANDARD': { next: 'CWF-110', pack: 'WF-100', decision: 'STANDARD_TOPIC_INTELLIGENCE' },
  'ROUTE_PHASE1_FAST': { next: 'CWF-110', pack: 'WF-100', decision: 'FAST_PATH_TOPIC_INTELLIGENCE' },
  'ROUTE_PHASE1_REPLAY': { next: $json.replay_target_workflow || 'CWF-110', pack: 'WF-100', decision: 'REPLAY_ROUTE_SELECTED' }
};
const routeConfig = routeMap[routeId] || routeMap['ROUTE_PHASE1_STANDARD'];
nextWorkflow = routeConfig.next;
orchestration_decision = routeConfig.decision;
return [{
  json: {
    ...$json,
    orchestration_decision: {
      route_selected: routeId,
      next_workflow: nextWorkflow,
      next_pack: routeConfig.pack,
      decision: orchestration_decision,
      repo_present: true,
      approval_gates_pending: ['topic_research_gate', 'script_approval_gate']
    }
  }
}];

try {
  const decision = $json.orchestration_decision;
  if (!decision || !decision.route_selected || !decision.next_workflow) {
    throw new Error('missing orchestration decision fields');
  }
  return [{ json: { ...$json, validation_status: 'SUCCESS', route_to_error: false } }];
} catch (error) {
  return [{ json: { ...$json, validation_status: 'FAILED', route_to_error: true, validation_error: String(error.message || error) } }];
}

if ($json.route_to_error) return [];
const fs = require('fs');
const path = require('path');

const now = new Date().toISOString();
const dossierId = $json.dossier_id || ($json.dossier_context && $json.dossier_context.dossier_id) || 'DOSSIER-UNSPECIFIED';
const routeSelected = ($json.orchestration_decision && $json.orchestration_decision.route_selected) || $json.route_id || 'ROUTE_PHASE1_STANDARD';

const repoRoot = 'C:/ShadowEmpire-Git';
const dossiersDir = path.join(repoRoot, 'dossiers');
const dataDir = path.join(repoRoot, 'data');
const dossierPath = path.join(dossiersDir, dossierId + '.json');
const indexPath = path.join(dataDir, 'se_dossier_index.json');

if (!fs.existsSync(dossiersDir)) fs.mkdirSync(dossiersDir, { recursive: true });
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });

let dossier = {
  dossier_id: dossierId,
  route_id: routeSelected,
  created_at: now,
  status: 'active',
  namespaces: {},
  _version: 0,
  _created_at: now,
  _audit_trail: []
};
if (fs.existsSync(dossierPath)) {
  try {
    const parsed = JSON.parse(fs.readFileSync(dossierPath, 'utf8'));
    dossier = {
      ...dossier,
      ...parsed,
      namespaces: typeof parsed.namespaces === 'object' && parsed.namespaces ? parsed.namespaces : {},
      _audit_trail: Array.isArray(parsed._audit_trail) ? parsed._audit_trail : []
    };
  } catch (e) {
    throw new Error('WF-010 persistence failed: dossier parse error: ' + e.message);
  }
}

const runtimeNs = (dossier.namespaces.runtime && typeof dossier.namespaces.runtime === 'object') ? dossier.namespaces.runtime : {};
const runs = Array.isArray(runtimeNs.orchestration_runs) ? runtimeNs.orchestration_runs : [];
runs.push({
  timestamp: now,
  workflow_id: 'WF-010',
  route_selected: routeSelected,
  decision: ($json.orchestration_decision && $json.orchestration_decision.decision) || 'STANDARD_PATH'
});
runtimeNs.orchestration_runs = runs;
runtimeNs.last_orchestration_status = 'ORCHESTRATION_COMPLETE';
runtimeNs.last_orchestration_at = now;
dossier.namespaces.runtime = runtimeNs;
dossier.current_workflow = 'WF-010';
dossier.last_updated = now;
dossier.status = 'ORCHESTRATION_COMPLETE';
dossier._version = Number(dossier._version || 0) + 1;
dossier._last_updated_at = now;
dossier._audit_trail.push({
  timestamp: now,
  workflow_id: 'WF-010',
  operation: 'ORCHESTRATION_UPDATE',
  route_selected: routeSelected,
  notes: 'append orchestration runtime state'
});

fs.writeFileSync(dossierPath, JSON.stringify(dossier, null, 2), 'utf8');

let index = {
  table: 'se_dossier_index',
  description: 'Index of all dossiers; updated by WF-001 and dossier_writer.',
  records: [],
  created_at: now,
  last_updated: now
};
if (fs.existsSync(indexPath)) {
  index = JSON.parse(fs.readFileSync(indexPath, 'utf8'));
  index.records = Array.isArray(index.records) ? index.records : [];
} else {
  index.records = [];
}
const existing = index.records.find((r) => r && r.dossier_id === dossierId);
if (existing) {
  existing.updated_at = now;
  existing.status = 'active';
  existing.route_id = routeSelected;
  existing.source_workflow = 'WF-010 Parent Orchestrator Canonical';
} else {
  index.records.push({
    dossier_id: dossierId,
    status: 'active',
    created_at: now,
    updated_at: now,
    route_id: routeSelected,
    source_workflow: 'WF-010 Parent Orchestrator Canonical'
  });
}
index.last_updated = now;
fs.writeFileSync(indexPath, JSON.stringify(index, null, 2), 'utf8');

return [{
  json: {
    ...$json,
    persistence: {
      wf: 'WF-010',
      dossier_path: dossierPath,
      dossier_index_path: indexPath,
      dossier_version: dossier._version,
      persisted_at: now
    },
    dossier_write: {
      mutation_type: 'update_status',
      target: 'dossier.runtime',
      timestamp: now,
      writer_id: 'WF-010',
      instance_id: dossierId,
      new_status: 'ORCHESTRATION_COMPLETE',
      audit_entry: 'route-selection and orchestration from WF-010'
    }
  }
}];

if ($json.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_workflow_execution',
      workflow_id: 'WF-010',
      dossier_id: $json.dossier_id,
      route_id: $json.orchestration_decision.route_selected,
      orchestration_decision: $json.orchestration_decision.decision,
      execution_timestamp: new Date().toISOString(),
      status: 'COMPLETED'
    }
  }
}];

// Capture wf100_result
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Route Selection Node').first().json || {}; } catch(e) {}
let dossierCtx = {};
try { dossierCtx = $('Dossier Load Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx, dossier_id: dossierCtx.dossier_id || parentCtx.dossier_id };

acc["wf100_result"] = {
  status: (() => { const s = (subOutput.execution_status || subOutput.status || (subOutput.error ? 'ERROR' : '') || '').toString().toUpperCase(); return s || 'SUCCESS'; })(),
  payload: subOutput.completion_packet || subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

